import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { phongAPI, thanhToanAPI, yeuCauAPI } from '../services/api';
import { buildPhongAddress } from '../utils/location';
import './QuanLyPhong.css';

const fmt = n => new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(n || 0);

function DotIcon() {
  return (
    <svg viewBox="0 0 24 24" aria-hidden="true">
      <circle cx="6" cy="12" r="1.9" fill="currentColor" />
      <circle cx="12" cy="12" r="1.9" fill="currentColor" />
      <circle cx="18" cy="12" r="1.9" fill="currentColor" />
    </svg>
  );
}

export default function QuanLyPhong() {
  const navigate = useNavigate();
  const [phongs, setPhongs] = useState([]);
  const [yeuCaus, setYeuCaus] = useState({});
  const [selectedPhong, setSelectedPhong] = useState(null);
  const [loading, setLoading] = useState(true);
  const [deletingPhongId, setDeletingPhongId] = useState(null);
  const [memberMenu, setMemberMenu] = useState(null);
  const menuRef = useRef(null);

  const fetchPhongs = async () => {
    setLoading(true);
    try {
      const res = await phongAPI.layPhongCuaToi();
      setPhongs(res.data.data || []);
    } catch {
      toast.error('Không tải được danh sách phòng');
    }
    setLoading(false);
  };

  const fetchYeuCau = async maPhong => {
    try {
      const res = await yeuCauAPI.layCuaPhong(maPhong);
      setYeuCaus(prev => ({ ...prev, [maPhong]: res.data.data || [] }));
    } catch {
      toast.error('Không tải được yêu cầu tham gia');
    }
  };

  useEffect(() => {
    fetchPhongs();
  }, []);

  useEffect(() => {
    const handleClickOutside = event => {
      if (menuRef.current && !menuRef.current.contains(event.target)) {
        setMemberMenu(null);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const phongDangMoMenu = useMemo(
    () => phongs.find(item => item.maPhong === memberMenu?.maPhong) || null,
    [memberMenu, phongs]
  );

  const handleDuyet = async (maYeuCau, chapNhan, maPhong) => {
    try {
      await yeuCauAPI.duyet(maYeuCau, chapNhan);
      toast.success(chapNhan ? 'Đã chấp nhận yêu cầu' : 'Đã từ chối yêu cầu');
      fetchPhongs();
      fetchYeuCau(maPhong);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Thất bại');
    }
  };

  const handleChiaTien = async maPhong => {
    try {
      await thanhToanAPI.chiaTien(maPhong);
      toast.success('Đã tạo hóa đơn chia tiền cho các thành viên');
      setMemberMenu(null);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Thất bại');
    }
  };

  const handleXoaThanhVien = async (maPhong, maThanhVien) => {
    if (!window.confirm('Bạn có chắc muốn xóa thành viên này khỏi phòng không?')) {
      return;
    }

    try {
      await phongAPI.xoaThanhVien(maPhong, maThanhVien);
      toast.success('Đã xóa thành viên khỏi phòng');
      setMemberMenu(null);
      fetchPhongs();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Xóa thành viên thất bại');
    }
  };

  const handleDoiTrangThai = async (maPhong, trangThai) => {
    try {
      await phongAPI.capNhat(maPhong, { trangThai });
      toast.success('Cập nhật trạng thái thành công');
      fetchPhongs();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Thất bại');
    }
  };

  const handleDeletePhong = async maPhong => {
    if (!window.confirm('Bạn có chắc muốn xóa phòng này không?')) return;

    setDeletingPhongId(maPhong);
    try {
      await phongAPI.xoa(maPhong);
      setPhongs(current => current.filter(phong => phong.maPhong !== maPhong));
      setSelectedPhong(current => (current === maPhong ? null : current));
      setYeuCaus(current => {
        const next = { ...current };
        delete next[maPhong];
        return next;
      });
      toast.success('Đã xóa phòng thành công');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Xóa phòng thất bại');
    }
    setDeletingPhongId(null);
  };

  if (loading) return <div className="spinner" />;

  return (
    <div className="container page-wrapper">
      <div className="page-title-row">
        <h1 className="section-title" style={{ marginBottom: 0 }}>Quản lý phòng</h1>
        <Link to="/tao-phong" className="btn btn-primary">Thêm phòng mới</Link>
      </div>

      {phongs.length === 0 ? (
        <div className="empty-state card">
          <div className="card-body">
            <div className="empty-state-icon">🏠</div>
            <p>Bạn chưa có phòng nào. <Link to="/tao-phong">Tạo phòng ngay</Link></p>
          </div>
        </div>
      ) : (
        <div className="phong-manage-list">
          {phongs.map(phong => (
            <div key={phong.maPhong} className="card phong-manage-card">
              <div className="phong-manage-header">
                <div>
                  <h3>{phong.title}</h3>
                  <div className="phong-manage-subtitle">
                    {buildPhongAddress(phong)} · {fmt(phong.giaTien)}/tháng
                  </div>
                </div>

                <div className="phong-manage-header-actions">
                  <span className={`badge ${
                    phong.trangThai === 'San sang'
                      ? 'badge-success'
                      : phong.trangThai === 'Da day'
                        ? 'badge-danger'
                        : 'badge-warning'
                  }`}>
                    {phong.trangThai === 'San sang'
                      ? 'Sẵn sàng'
                      : phong.trangThai === 'Da day'
                        ? 'Đã đầy'
                        : 'Bảo trì'}
                  </span>

                  <select
                    className="form-control phong-status-select"
                    value={phong.trangThai}
                    onChange={e => handleDoiTrangThai(phong.maPhong, e.target.value)}
                  >
                    <option value="San sang">Sẵn sàng</option>
                    <option value="Da day">Đã đầy</option>
                    <option value="Bao tri">Bảo trì</option>
                  </select>
                </div>
              </div>

              <div className="phong-manage-body">
                <div className="phong-manage-main">
                  <div className="room-cost-grid">
                    <div className="room-cost-card">
                      <span>Giá phòng</span>
                      <strong>{fmt(phong.giaTien)}/tháng</strong>
                    </div>
                    <div className="room-cost-card">
                      <span>Tiền dịch vụ</span>
                      <strong>{fmt(phong.tienDichVu)}</strong>
                    </div>
                    <div className="room-cost-card">
                      <span>Tiền điện</span>
                      <strong>{fmt(phong.tienDien)}</strong>
                    </div>
                    <div className="room-cost-card">
                      <span>Tiền nước</span>
                      <strong>{fmt(phong.tienNuoc)}</strong>
                    </div>
                  </div>

                  <div className="members-section">
                    <h4>Thành viên phòng ({phong.soNguoiHienTai}/{phong.soNguoiToiDa})</h4>
                    <div className="members-list-column">
                      {phong.danhSachThanhVien?.map(member => (
                        <div key={member.maNguoiDung} className="member-row">
                          <Link
                            to={`/nguoi-dung/${member.maNguoiDung}`}
                            className="member-profile-link member-row-link"
                          >
                            <img
                              src={member.avatar || `https://ui-avatars.com/api/?name=${encodeURIComponent(member.hoTen)}&background=12355B&color=fff&size=40`}
                              className="avatar avatar-sm"
                              alt={member.hoTen}
                            />
                            <div className="member-row-text">
                              <strong>{member.hoTen}</strong>
                              <span>{member.ngayThamGia ? `Vào phòng: ${new Date(member.ngayThamGia).toLocaleDateString('vi-VN')}` : 'Thành viên hiện tại'}</span>
                            </div>
                          </Link>

                          <div className="member-menu-wrap" ref={memberMenu?.maThanhVien === member.maNguoiDung && memberMenu?.maPhong === phong.maPhong ? menuRef : null}>
                            <button
                              type="button"
                              className="member-menu-trigger"
                              onClick={() => setMemberMenu(current => (
                                current?.maPhong === phong.maPhong && current?.maThanhVien === member.maNguoiDung
                                  ? null
                                  : { maPhong: phong.maPhong, maThanhVien: member.maNguoiDung }
                              ))}
                            >
                              <DotIcon />
                            </button>

                            {memberMenu?.maPhong === phong.maPhong && memberMenu?.maThanhVien === member.maNguoiDung && (
                              <div className="member-menu-dropdown">
                                <button
                                  type="button"
                                  className="member-menu-item"
                                  onClick={() => handleXoaThanhVien(phong.maPhong, member.maNguoiDung)}
                                >
                                  Xóa thành viên
                                </button>
                                <button
                                  type="button"
                                  className="member-menu-item"
                                  onClick={() => handleChiaTien(phong.maPhong)}
                                >
                                  Chia tiền phòng
                                </button>
                              </div>
                            )}
                          </div>
                        </div>
                      ))}

                      {phong.danhSachThanhVien?.length === 0 && (
                        <p className="member-empty">Chưa có thành viên</p>
                      )}
                    </div>
                  </div>
                </div>

                <div className="phong-actions">
                  <button
                    className="btn btn-outline btn-sm"
                    onClick={() => navigate(`/phong/${phong.maPhong}/chinh-sua`)}
                  >
                    Chỉnh sửa phòng
                  </button>
                  <button
                    className="btn btn-secondary btn-sm"
                    onClick={() => {
                      fetchYeuCau(phong.maPhong);
                      setSelectedPhong(current => (current === phong.maPhong ? null : phong.maPhong));
                    }}
                  >
                    {selectedPhong === phong.maPhong ? 'Ẩn yêu cầu' : 'Xem yêu cầu'}
                  </button>
                  <button
                    className="btn btn-danger btn-sm"
                    onClick={() => handleDeletePhong(phong.maPhong)}
                    disabled={deletingPhongId === phong.maPhong}
                  >
                    {deletingPhongId === phong.maPhong ? 'Đang xóa...' : 'Xóa phòng'}
                  </button>
                </div>
              </div>

              {selectedPhong === phong.maPhong && (
                <div className="yeu-cau-panel">
                  <h4>Yêu cầu tham gia</h4>
                  {(yeuCaus[phong.maPhong] || []).length === 0 ? (
                    <p className="member-empty">Chưa có yêu cầu nào.</p>
                  ) : (
                    (yeuCaus[phong.maPhong] || []).map(yc => (
                      <div key={yc.maYeuCau} className="yeu-cau-item">
                        <Link to={`/nguoi-dung/${yc.maNguoiDung}`} className="yeu-cau-user-link">
                          <img
                            src={yc.avatarNguoiDung || `https://ui-avatars.com/api/?name=${encodeURIComponent(yc.tenNguoiDung)}&size=40`}
                            className="avatar avatar-sm"
                            alt={yc.tenNguoiDung}
                          />
                          <div style={{ flex: 1 }}>
                            <strong>{yc.tenNguoiDung}</strong>
                            {yc.moTa && <p className="yeu-cau-note">{yc.moTa}</p>}
                          </div>
                        </Link>
                        <span className={`badge ${
                          yc.trangThai === 'Chap nhan'
                            ? 'badge-success'
                            : yc.trangThai === 'Tu choi'
                              ? 'badge-danger'
                              : 'badge-warning'
                        }`}>
                          {yc.trangThai === 'Chap nhan'
                            ? 'Đã chấp nhận'
                            : yc.trangThai === 'Tu choi'
                              ? 'Đã từ chối'
                              : 'Chờ duyệt'}
                        </span>
                        {yc.trangThai === 'Cho duyet' && (
                          <div className="yeu-cau-action-row">
                            <button className="btn btn-success btn-sm" onClick={() => handleDuyet(yc.maYeuCau, true, phong.maPhong)}>Duyệt</button>
                            <button className="btn btn-danger btn-sm" onClick={() => handleDuyet(yc.maYeuCau, false, phong.maPhong)}>Từ chối</button>
                          </div>
                        )}
                      </div>
                    ))
                  )}
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
